class Solution {
    fun twoSum(nums: IntArray, target: Int): IntArray {
        val indexMap = mutableMapOf<Int, MutableList<Int>>()  // 값과 인덱스를 저장할 맵

        // 배열을 순회하면서 값과 그 값의 인덱스를 맵에 추가
        nums.forEachIndexed { index, value ->
            indexMap.computeIfAbsent(value) { mutableListOf() }.add(index)
        }

        // 두 수의 합을 찾기
        for (index in nums.indices) {
            val complement = target - nums[index]
            // 보완 값이 맵에 있는지 확인
            if (indexMap.containsKey(complement)) {
                // 인덱스 리스트에서 현재 인덱스를 제외하고 반환
                val indices = indexMap[complement]
                if (indices != null) {
                    for (idx in indices) {
                        if (idx != index) {  // 현재 인덱스가 아니어야 함
                            return intArrayOf(index, idx)
                        }
                    }
                }
            }
        }
        return intArrayOf() // 결과를 찾지 못했을 경우 빈 배열 반환
    }
}

