class Solution {
    fun addTwoNumbers(l1: ListNode?, l2: ListNode?): ListNode? {
        var firstNode = l1
        var secondNode = l2
        var carry = 0
        val dummyHead = ListNode(0)
        var currentNode = dummyHead

        while (firstNode != null || secondNode != null || carry != 0) {
            val firstVal = firstNode?.`val` ?: 0
            val secondVal = secondNode?.`val` ?: 0

            // 현재 자리 수 더하고, 올림수(carry) 계산
            val sum = firstVal + secondVal + carry
            carry = sum / 10  // carry는 sum을 10으로 나눈 몫
            val digit = sum % 10  // 각 자릿수는 sum을 10으로 나눈 나머지

            // 새로운 노드를 생성하여 currentNode에 연결
            currentNode.next = ListNode(digit)
            currentNode = currentNode.next!!

            // 각 리스트의 다음 노드로 이동
            firstNode = firstNode?.next
            secondNode = secondNode?.next
        }

        return dummyHead.next
    }
}

