class Solution {
    fun maxArea(height: IntArray): Int {
        var maxArea = 0
        var left = 0
        var right = height.size - 1

        while (left < right) {
            val area = minOf(height[left], height[right]) * (right - left)
            maxArea = maxOf(maxArea, area)

            // Move the pointer pointing to the shorter height
            if (height[left] < height[right]) {
                left++
            } else {
                right--
            }
        }

        return maxArea
    }
}

class Solution {
    /*
    Data structure : array
    algo : search
    ps : two-pointer
    */
    fun threeSumClosest(nums: IntArray, target: Int): Int {
        nums.sort() // 정렬
        return (0 until nums.size - 2) // 마지막 두 요소를 제외한 인덱스
            .fold(Int.MAX_VALUE) { closestSum, i ->
                // 두 포인터 초기화
                var left = i + 1
                var right = nums.lastIndex

                var currentClosest = closestSum
                while (left < right) {
                    val currentSum = nums[i] + nums[left] + nums[right]

                    // 현재 가까운 값 갱신
                    if (Math.abs(target - currentSum) < Math.abs(target - currentClosest)) {
                        currentClosest = currentSum
                    }

                    when {
                        currentSum < target -> left++ // 타겟보다 작으면 왼쪽 포인터 이동
                        currentSum > target -> right-- // 타겟보다 크면 오른쪽 포인터 이동
                        else -> return currentSum // 정확히 일치하면 즉시 반환
                    }
                }

                // 더 가까운 값 반환
                if (Math.abs(target - currentClosest) < Math.abs(target - closestSum)) {
                    currentClosest
                } else {
                    closestSum
                }            }
    }
}

