class Solution {
    fun minWindow(s: String, t: String): String {
                if (s.length < t.length) return ""

        val targetMap = mutableMapOf<Char, Int>()
        val windowMap = mutableMapOf<Char, Int>()

        // Step 1: Count characters in `t`
        for (char in t) {
            targetMap[char] = targetMap.getOrDefault(char, 0) + 1
        }

        var left = 0
        var right = 0
        var formed = 0  // Number of characters in `windowMap` that meet the `targetMap` requirement
        var minLength = Int.MAX_VALUE
        var minLeft = 0

        while (right < s.length) {
            val charRight = s[right]
            windowMap[charRight] = windowMap.getOrDefault(charRight, 0) + 1

            // If the current character matches the count in targetMap, increment formed
            if (targetMap.containsKey(charRight) && windowMap[charRight] == targetMap[charRight]) {
                formed++
            }

            // Try to shrink the window from the left
            while (formed == targetMap.size) {
                // Update the minimum window
                if (right - left + 1 < minLength) {
                    minLength = right - left + 1
                    minLeft = left
                }

                val charLeft = s[left]
                windowMap[charLeft] = windowMap[charLeft]!! - 1

                // If removing `charLeft` makes the window invalid, decrease `formed`
                if (targetMap.containsKey(charLeft) && windowMap[charLeft]!! < targetMap[charLeft]!!) {
                    formed--
                }

                left++
            }

            right++
        }

        return if (minLength == Int.MAX_VALUE) "" else s.substring(minLeft, minLeft + minLength)
    }
}

