class Solution {
    fun maxDepth(root: TreeNode?): Int {
        // 끝까지 파다가 없으면 돌아가야되는데, 돌아 갈 때  TreeNode는 자식 노드 정보만 있는데 부모로 어떻게 돌아가지 ? 그것도 단순히 한번 돌아가는게 아닌, 탐색할 노드가 있을 때까지 돌아가야됨. -> 재귀 사용!
        return findMaxDepth(root, 1)
    }

    fun findMaxDepth(root: TreeNode?, depth: Int): Int {
        var maxDepth = depth
        if ((root?.left == null) && (root?.right == null))  return if (root == null) 0 else maxDepth
        root?.right?.let {
            maxDepth = max(maxDepth, findMaxDepth(it, depth + 1))
        }        

        root?.left?.let {
            maxDepth = max(maxDepth, findMaxDepth(it, depth + 1))
        }

        // println("value and depth : ${root.`val`}, $maxDepth")
        return maxDepth
    }
}

