class Solution {
    fun hasCycle(head: ListNode?): Boolean {
        // current.`val` :  노드 값.
        // current.next : 다음 노드 객체.
        var slowPoint = head
        var fastPoint = head?.next

        while (fastPoint != null) {
            if (slowPoint == fastPoint) return true
            slowPoint = slowPoint?.next
            fastPoint = fastPoint?.next?.next
        }
        return false
    }
}

