class Solution {

    data class TailInfo(
    val tail: ListNode?, 
    val length: Int
    )


    fun oddEvenList(head: ListNode?): ListNode? {
        var idx = 1
        var (tail, length) = _findTail(head)
        var beforeTarget = head
        var target: ListNode? = head?.next


        while(true) {
            if ((target?.next == null) or (idx == length)) break

            // beforeTarget보다 앞서있는 target 혹은 target.next가 Null이면 다음 로직을 타지 않으므로 beforeTarget과 target은 null이 아님을 강제함.(!!)
            if (idx%2 == 1 ) {
                beforeTarget!!.next = target!!.next
                target.next = null
                tail!!.next = target

                tail = target
                target = beforeTarget.next
                idx++
            } else {
                target = target!!.next
                beforeTarget = beforeTarget!!.next
                idx++
            }
        }

        return head
    }

    private fun _findTail(head: ListNode?): TailInfo {
        var current = head
        var length = 1

        while(true) {
            if(current?.next == null) break
            current = current.next
            length++
        }
    return TailInfo(current, length)
    }
}

