class Solution {
    fun findMaxAverage(nums: IntArray, k: Int): Double {
        /**
        * data structure : array.
        * algorithm : search.
        * problem solving : slide window.
         */

        if (nums.size < k) return -1.0
        var sum = 0.0
        var max = 0.0
        var idx = k-1

        nums.forEachIndexed { index, it -> 
            if (index < k-1) {
                sum += it
            } else if (index == k-1) {
                sum += it
                max = sum.toDouble() / k
            } else {
                sum += it
                sum -= nums[index-k]
                max = kotlin.math.max(max, sum.toDouble() /k)
            }
        }
        return max
    }
}

class Solution:
    def predictPartyVictory(self, senate: str) -> str:
        n = len(senate)
        radiant = deque()
        dire = deque()

        for i, s in enumerate(senate):
            if s == 'R':
                radiant.append(i)
            else:
                dire.append(i)

        while radiant and dire:
            r = radiant.popleft()
            d = dire.popleft()

            if r < d:
                radiant.append(r + n)
            else:
                dire.append(d + n)

        return "Radiant" if radiant else "Dire"

