        visited = [False] * n
        stack = [0]

        while stack:
            cur = stack.pop()
            if (visited[cur]): continue
            visited[cur] = True
            for next in rooms[cur]:
                if (visited[next] != True): stack.append(next)

        for visitedValue in visited:
