class Solution {
    fun leafSimilar(root1: TreeNode?, root2: TreeNode?): Boolean {
        return _leafValueSequence(root1, mutableListOf<Int>()) == _leafValueSequence(root2, mutableListOf<Int>())
    }

    private fun _leafValueSequence(root: TreeNode?, sequence: MutableList<Int>): MutableList<Int> {
        var seq = sequence
        if (root == null) return sequence
        if (root.left == null && root.right == null) {
            seq.add(root.`val`)
            return seq
        }
        if (root.left != null) seq = _leafValueSequence(root.left, seq)
        if (root.right != null) seq = _leafValueSequence(root.right, seq)

        return seq 
    }
}

