            if value not in nums2:
                answer[0].add(value)
        for value in nums2:
            if value not in nums1:
                answer[1].add(value)

        answer[0] = list(answer[0])
        answer[1] = list(answer[1])
        return answer

class Solution:
    def removeStars(self, s: str) -> str:
        stack = []
        for char in s:
            if char == '*':
                if stack:
                    stack.pop()
            else:
                stack.append(char)
        return ''.join(stack)

