    fun compressedString(word: String): String {
        var cnt = 0
        var answer = StringBuilder()
        word.forEachIndexed { index, ch -> 
            if (index == 0) {cnt++}
            else {
                if (ch == word[index-1] && cnt !== 9) cnt++
                else {
                    answer.append(cnt.toString())
                    answer.append(word[index-1])
                    cnt = 1
                }
